async (params, browser) => {
  // Open page
  await browser.open(`https://www.strava.com/clubs/${params.club_id}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="Club"], .club-heading', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1, [class*="ClubName"]')?.textContent?.trim()||''; const desc = document.querySelector('[class*="Description"], .club-description')?.textContent?.trim()?.substring(0,500)||''; const memberCount = document.body.innerText.match(/(\d[\d,]*)\s*members?/i)?.[1]||''; const sport = document.querySelector('[class*="sport"], .club-type')?.textContent?.trim()||''; return { club_id: '' + params.club_id + '', name, description: desc, members: memberCount, sport, url: window.location.href }`)

  return page_data
}
